#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
#define int long long
using pii=pair<int,int>;
struct node{
	vector<pair<int,int>>e;
	int d=INT_MAX;
}v[maxn];
priority_queue<pii,vector<pii>,greater<pii>>pq;
int n,m,s;
signed main(){
	cin>>n>>m>>s;
	for(int i=1,x,y,z;i<=m;i++){
		cin>>x>>y>>z;
		v[x].e.emplace_back(z,y);
	}
	pq.push({0,s});
	while(pq.size()){
		auto p=pq.top();
		pq.pop();
		if(v[p.second].d==INT_MAX){
			v[p.second].d=p.first;
			for(auto x:v[p.second].e){
				pq.push({x.first+p.first,x.second});
			}
		}
	}
	for(int i=1;i<=n;i++){
		cout<<v[i].d<<" ";
	}
	return 0;
}
